        self.employee_id = employee_id
        self.employee_name = employee_name
        self.manager_id = manager_id

class Company:
    def __init__(self):
        self.employees = {}

    def add_employee(self, employee_id, employee_name, manager_id):
        self.employees[employee_id] = Employee(employee_id, employee_name, manager_id)

    def calculate_pecking_order(self):
        pecking_order = {}
        for employee_id, employee in self.employees.items():
            level = 1
            manager_id = employee.manager_id
            while manager_id != '0':
                level += 1
                manager = self.employees.get(manager_id)
                if manager:
                    manager_id = manager.manager_id
                else:
                    break
            pecking_order[employee_id] = level
        return pecking_order

    def count_subordinates(self):
        subordinate_count = {}
        for employee_id, employee in self.employees.items():
            count = 0
            for other_employee in self.employees.values():
                if other_employee.manager_id == employee_id:
                    count += 1
                    count += self.count_subordinates_recursive(other_employee.employee_id)
            subordinate_count[employee_id] = count
        return subordinate_count

    def count_subordinates_recursive(self, employee_id):
        count = 0
        for other_employee in self.employees.values():
            if other_employee.manager_id == employee_id:
                count += 1
                count += self.count_subordinates_recursive(other_employee.employee_id)
        return count

    def calculate_manager_chain(self):
        manager_chain = {}
        for employee_id, employee in self.employees.items():
            chain = []
            manager_id = employee.manager_id
            while manager_id != '0':
                manager = self.employees.get(manager_id)
                if manager:
                    chain.append(manager.employee_name)
                    manager_id = manager.manager_id
                else:
                    break
            manager_chain[employee_id] = ' > '.join(chain)
        return manager_chain

