class Company:
    def __init__(self):
        self.employees = {}

    def add_employee(self, employee_id, employee_name, manager_id):
        self.employees[employee_id] = Employee(employee_id, employee_name, manager_id)

    def build_hierarchy(self):
        for employee in self.employees.values():
            if employee.manager_id in self.employees:
                self.employees[employee.manager_id].subordinates.append(employee)

    def calculate_pecking_order(self):
        pecking_order = {}
        for employee in self.employees.values():
            if employee.manager_id is None or employee.manager_id not in self.employees:
                pecking_order[employee.employee_id] = 1
            else:
                pecking_order[employee.employee_id] = pecking_order.get(employee.manager_id, 0) + 1
        return pecking_order

    def calculate_subordinate_count(self):
        subordinate_count = {}
        for employee in self.employees.values():
            subordinate_count[employee.employee_id] = len(employee.subordinates)
        return subordinate_count

    def calculate_manager_chain(self):
        manager_chain = {}
        for employee in self.employees.values():
            chain = []
            current_employee = employee
            while current_employee:
                chain.append(current_employee.employee_name)
                if current_employee.manager_id in self.employees:
                    current_employee = self.employees[current_employee.manager_id]
                else:
                    current_employee = None
            manager_chain[employee.employee_id] = ' > '.join(reversed(chain))
        return manager_chain

    def print_results(self, pecking_order, subordinate_count, manager_chain):
        print("Pecking Order:")
        print("| employee_id | employee_name | level |")
        print("| - - - - - - - - - - - - - | - - - - - - - - - - - - - - - | - - - - - - - |")
        for employee_id, level in pecking_order.items():
            employee = self.employees[employee_id]
            print(f"| {employee_id} | {employee.employee_name} | {level} |")

        print("\nSubordinate Count:")
        print("| employee_id | employee_name | subordinate_count |")
        print("| - - - - - - - - - - - - - | - - - - - - - - - - - - - - - | - - - - - - - - - - - - - - - - - - - |")
        for employee_id, count in subordinate_count.items():
            employee = self.employees[employee_id]
            print(f"| {employee_id} | {employee.employee_name} | {count} |")

        print("\nManager Chain:")
        print("| employee_id | employee_name | manager_chain |")
        print("| - - - - - - - - - - - - - | - - - - - - - - - - - - - - - | - - - - - - - - - - - - - - - - - - - |")
        for employee_id, chain in manager_chain.items():
            employee = self.employees[employee_id]
            print(f"| {employee_id} | {employee.employee_name} | {chain} |")

