class Company:
    def __init__(self):
        self.employees = {}

    def add_employee(self, employee_id, employee_name, manager_id):
        self.employees[employee_id] = Employee(employee_id, employee_name, manager_id)

    def build_hierarchy(self):
        for employee in self.employees.values():
            if employee.manager_id in self.employees:
                self.employees[employee.manager_id].subordinates.append(employee)

    def calculate_pecking_order(self):
        pecking_order = {}
        def dfs(employee_id, level):
            if employee_id not in pecking_order:
                pecking_order[employee_id] = level
                for subordinate in self.employees[employee_id].subordinates:
                    dfs(subordinate.employee_id, level + 1)
        dfs(list(self.employees.keys())[0], 1)
        return pecking_order

    def calculate_subordinate_count(self):
        subordinate_count = {}
        def dfs(employee_id):
            count = 0
            for subordinate in self.employees[employee_id].subordinates:
                count += 1 + dfs(subordinate.employee_id)
            subordinate_count[employee_id] = count
            return count
        for employee in self.employees.values():
            if employee.manager_id not in self.employees:
                dfs(employee.employee_id)
        return subordinate_count

    def calculate_manager_chain(self):
        manager_chain = {}
        def dfs(employee_id, chain):
            if employee_id not in manager_chain:
                manager_chain[employee_id] = chain
                if self.employees[employee_id].manager_id in self.employees:
                    dfs(self.employees[employee_id].manager_id, chain + ' > ' + self.employees[self.employees[employee_id].manager_id].employee_name)
        for employee in self.employees.values():
            if employee.manager_id not in self.employees:
                dfs(employee.employee_id, employee.employee_name)
            else:
                dfs(employee.employee_id, employee.employee_name)
        return manager_chain

    def print_results(self):
        pecking_order = self.calculate_pecking_order()
        subordinate_count = self.calculate_subordinate_count()
        manager_chain = self.calculate_manager_chain()

