            print(f"| {employee_id} | {employee_name} | {pecking_order[employee_id]} |")

        print("\nSubordinate Count:")
        print("| employee_id | employee_name | subordinate_count |")
        print("| - - - - - - - - - - - - - | - - - - - - - - - - - - - - - | - - - - - - - - - - - - - - - - - - - |")
        for employee_id, employee_name in [(employee_id, self.employees[employee_id].employee_name) for employee_id in self.employees]:
            print(f"| {employee_id} | {employee_name} | {subordinate_count[employee_id]} |")

        print("\nManager Chain:")
        print("| employee_id | employee_name | manager_chain |")
        print("| - - - - - - - - - - - - - | - - - - - - - - - - - - - - - | - - - - - - - - - - - - - - - - - - - |")
        for employee_id, employee_name in [(employee_id, self.employees[employee_id].employee_name) for employee_id in self.employees]:
