class HierarchyAnalyzer:
    def __init__(self, employees):
        self.employees = {employee.employee_id: employee for employee in employees}
        self.ceo = next((employee for employee in employees if employee.manager_id is None), None)
        self.build_hierarchy()

    def build_hierarchy(self):
        for employee in self.employees.values():
            if employee.manager_id is not None:
                manager = self.employees[employee.manager_id]
                manager.subordinates.append(employee)

        self.assign_levels(self.ceo, 1)
        self.build_manager_chains()

    def assign_levels(self, employee, level):
        employee.level = level
        for subordinate in employee.subordinates:
            self.assign_levels(subordinate, level + 1)

    def build_manager_chains(self):
        for employee in self.employees.values():
            if employee.manager_id is not None:
                manager = self.employees[employee.manager_id]
                employee.manager_chain = [manager.employee_name]
                while manager.manager_id is not None:
                    manager = self.employees[manager.manager_id]
                    employee.manager_chain.insert(0, manager.employee_name)
                employee.manager_chain = ' > '.join(employee.manager_chain)

    def get_hierarchy_levels(self):
        result = []
        for employee in self.employees.values():
            result.append((employee.employee_id, employee.employee_name, employee.level))
        return result

    def get_subordinate_counts(self):
        result = []
        for employee in self.employees.values():
            subordinate_count = self.count_subordinates(employee)
            result.append((employee.employee_id, employee.employee_name, subordinate_count))
        return result

    def count_subordinates(self, employee):
        if not employee.subordinates:
            return 0
        count = len(employee.subordinates)
        for subordinate in employee.subordinates:
            count += self.count_subordinates(subordinate)
        return count

    def get_manager_chains(self):
        result = []
        for employee in self.employees.values():
            if employee.manager_id is None:
                manager_chain = None
            else:
                manager_chain = employee.manager_chain
            result.append((employee.employee_id, employee.employee_name, manager_chain))
        return result

