    def __init__(self, employees):
        self.employees = {employee.employee_id: employee for employee in employees}
        self.ceo = next((employee for employee in employees if employee.manager_id is None), None)
        self.build_hierarchy()

    def build_hierarchy(self):
        for employee in self.employees.values():
            if employee.manager_id is not None:
                manager = self.employees.get(employee.manager_id)
                if manager:
                    manager.subordinates.append(employee)
        self.assign_levels()
        self.build_manager_chain()

    def assign_levels(self):
        self.assign_level(self.ceo, 1)

    def assign_level(self, employee, level):
        employee.level = level
        for subordinate in employee.subordinates:
            self.assign_level(subordinate, level + 1)

    def build_manager_chain(self):
        for employee in self.employees.values():
            if employee != self.ceo:
                self.build_chain(employee)

    def build_chain(self, employee):
        manager = self.employees.get(employee.manager_id)
        if manager:
            employee.manager_chain.append(manager.employee_name)
            self.build_chain(manager)

    def get_hierarchy_level(self):
        return [(employee.employee_id, employee.employee_name, employee.level) for employee in self.employees.values()]

    def get_subordinate_count(self):
        counts = []
        for employee in self.employees.values():
            count = self.count_subordinates(employee)
            counts.append((employee.employee_id, employee.employee_name, count))
        return counts

    def count_subordinates(self, employee):
        count = 0
        for subordinate in employee.subordinates:
            count += 1 + self.count_subordinates(subordinate)
        return count

    def get_manager_chain(self):
        chains = []
        for employee in self.employees.values():
            chain = ' > '.join(reversed(employee.manager_chain)) if employee.manager_chain else 'NULL'
            chains.append((employee.employee_id, employee.employee_name, chain))
        return chains

