import pandas as pd

def calculate_pecking_order(df):
    pecking_order = []
    for index, row in df.iterrows():
        level = 1
        manager_id = row['manager_id']
        while manager_id != None:
            level += 1
            manager_row = df.loc[df['employee_id'] == manager_id]
            if not manager_row.empty:
                manager_id = manager_row['manager_id'].values[0]
            else:
                manager_id = None
        pecking_order.append({'employee_id': row['employee_id'], 'employee_name': row['employee_name'], 'level': level})
    return pd.DataFrame(pecking_order)

def calculate_subordinate_count(df):
    subordinate_count = []
    for index, row in df.iterrows():
        count = 0
        employee_id = row['employee_id']
        for index2, row2 in df.iterrows():
            if row2['manager_id'] == employee_id:
                count += 1
                count += calculate_subordinate_count_helper(df, row2['employee_id'])
        subordinate_count.append({'employee_id': row['employee_id'], 'employee_name': row['employee_name'], 'subordinate_count': count})
    return pd.DataFrame(subordinate_count)

def calculate_subordinate_count_helper(df, employee_id):
    count = 0
    for index, row in df.iterrows():
        if row['manager_id'] == employee_id:
            count += 1
            count += calculate_subordinate_count_helper(df, row['employee_id'])
    return count

def calculate_manager_chain(df):
    manager_chain = []
    for index, row in df.iterrows():
        chain = ''
        manager_id = row['manager_id']
        while manager_id != None:
            manager_row = df.loc[df['employee_id'] == manager_id]
            if not manager_row.empty:
                chain = manager_row['employee_name'].values[0] + '>' + chain
                manager_id = manager_row['manager_id'].values[0]
            else:
                manager_id = None
        manager_chain.append({'employee_id': row['employee_id'], 'employee_name': row['employee_name'], 'manager_chain': chain})
    return pd.DataFrame(manager_chain)

