import pandas as pd

def get_pecking_order(df):
    df_copy = df.copy()
    df_copy['level'] = 0
    df_copy.loc[df_copy['manager_id'] == 0, 'level'] = 1
    df_copy.loc[df_copy['manager_id'] != 0, 'level'] = df_copy.apply(lambda row: get_level(df_copy, row['manager_id']), axis=1)
    return df_copy[['employee_id', 'employee_name', 'level']]

def get_level(df, manager_id):
    level = df.loc[df['employee_id'] == manager_id, 'level'].iloc[0]
    if pd.isnull(level):
        level = get_level(df, df.loc[df['employee_id'] == manager_id, 'manager_id'].iloc[0]) + 1
    return level

def get_subordinate_count(df):
    df_copy = df.copy()
    df_copy['subordinate_count'] = df_copy.apply(lambda row: get_subordinate_count_recursive(df_copy, row['employee_id']), axis=1)
    return df_copy[['employee_id', 'employee_name', 'subordinate_count']]

def get_subordinate_count_recursive(df, employee_id):
    count = 0
    for index, row in df.iterrows():
        if row['manager_id'] == employee_id:
            count += 1 + get_subordinate_count_recursive(df, row['employee_id'])
    return count

def get_manager_chain(df):
    df_copy = df.copy()
    df_copy['manager_chain'] = df_copy.apply(lambda row: get_manager_chain_recursive(df_copy, row['employee_id'], ''), axis=1)
    return df_copy[['employee_id', 'employee_name', 'manager_chain']]

def get_manager_chain_recursive(df, employee_id, manager_chain):
    manager_id = df.loc[df['employee_id'] == employee_id, 'manager_id'].iloc[0]
    if manager_id == 0:
        return manager_chain
    else:
        manager_name = df.loc[df['employee_id'] == manager_id, 'employee_name'].iloc[0]
        return get_manager_chain_recursive(df, manager_id, manager_name + '>' + manager_chain) if manager_chain else manager_name

