import pandas as pd

def calculate_hierarchy(df):
    # Create a dictionary to store the employee hierarchy
    hierarchy = {}
    for index, row in df.iterrows():
        hierarchy[row['employee_id']] = row['manager_id']

    # Calculate the level of each employee
    levels = {}
    def get_level(employee_id, level=1):
        if employee_id not in hierarchy or hierarchy[employee_id] is None or pd.isnull(hierarchy[employee_id]):
            return level
        else:
            return get_level(hierarchy[employee_id], level + 1)

    for employee_id in hierarchy:
        levels[employee_id] = get_level(employee_id)

    # Calculate the number of subordinates for each employee
    subordinates = {}
    def get_subordinates(employee_id):
        count = 0
        for emp_id, manager_id in hierarchy.items():
            if manager_id == employee_id:
                count += 1 + get_subordinates(emp_id)
        return count

    for employee_id in hierarchy:
        subordinates[employee_id] = get_subordinates(employee_id)

    # Calculate the manager chain for each employee
    manager_chains = {}
    def get_manager_chain(employee_id):
        chain = ''
        while employee_id in hierarchy and hierarchy[employee_id] is not None and not pd.isnull(hierarchy[employee_id]):
            chain = hierarchy[employee_id] + '>' + chain if chain else hierarchy[employee_id]
            employee_id = hierarchy[employee_id]
        return chain

    for employee_id in hierarchy:
        manager_chains[employee_id] = get_manager_chain(employee_id)

    # Create dataframes for the results
    level_df = pd.DataFrame({'employee_id': list(levels.keys()), 'employee_name': [df.loc[df['employee_id'] == emp_id, 'employee_name'].values[0] for emp_id in levels], 'level': list(levels.values())})
    subordinate_df = pd.DataFrame({'employee_id': list(subordinates.keys()), 'employee_name': [df.loc[df['employee_id'] == emp_id, 'employee_name'].values[0] for emp_id in subordinates], 'subordinate_count': list(subordinates.values())})
    manager_chain_df = pd.DataFrame({'employee_id': list(manager_chains.keys()), 'employee_name': [df.loc[df['employee_id'] == emp_id, 'employee_name'].values[0] for emp_id in manager_chains], 'manager_chain': list(manager_chains.values())})

    return level_df, subordinate_df, manager_chain_df

