import pandas as pd

def calculate_hierarchy(df):
    # Create a dictionary to store the manager chain for each employee
    manager_chain = {}

    # Function to get the manager chain for an employee
    def get_manager_chain(employee_id):
        if employee_id not in manager_chain:
            manager_id = df.loc[df['employee_id'] == employee_id, 'manager_id'].values[0]
            if pd.isnull(manager_id):
                manager_chain[employee_id] = ''
            else:
                manager_chain[employee_id] = get_manager_chain(manager_id) + '>' + df.loc[df['employee_id'] == manager_id, 'employee_name'].values[0] if manager_chain.get(manager_id) else get_manager_chain(manager_id)
        return manager_chain[employee_id]

    # Calculate the hierarchy level for each employee
    df['level'] = df.apply(lambda row: get_level(row['employee_id'], df), axis=1)

    # Function to get the hierarchy level for an employee
    def get_level(employee_id, df):
        if df.loc[df['employee_id'] == employee_id, 'manager_id'].values[0] is None or pd.isnull(df.loc[df['employee_id'] == employee_id, 'manager_id'].values[0]):
            return 1
        else:
            return get_level(df.loc[df['employee_id'] == employee_id, 'manager_id'].values[0], df) + 1

    # Calculate the subordinate count for each employee
    df['subordinate_count'] = df.apply(lambda row: get_subordinate_count(row['employee_id'], df), axis=1)

    # Function to get the subordinate count for an employee
    def get_subordinate_count(employee_id, df):
        count = 0
        for index, row in df.iterrows():
            if row['manager_id'] == employee_id:
                count += 1 + get_subordinate_count(row['employee_id'], df)
        return count

    # Calculate the manager chain for each employee
    df['manager_chain'] = df.apply(lambda row: get_manager_chain(row['employee_id']), axis=1)

    return df

