from collections import deque

def analyze_power_structure(employees):
    # Create a dictionary to store the employees and their managers
    employee_dict = {employee['employee_id']: employee for employee in employees}

    # Create a dictionary to store the manager chain for each employee
    manager_chain = {}

    # Create a dictionary to store the power structure level for each employee
    power_structure_level = {}

    # Create a dictionary to store the subordinate count for each employee
    subordinate_count = {}

    # Function to calculate the power structure level
    def calculate_power_structure_level(employee_id):
        if employee_id not in power_structure_level:
            if employee_dict[employee_id]['manager_id'] is None:
                power_structure_level[employee_id] = 1
            else:
                power_structure_level[employee_id] = calculate_power_structure_level(employee_dict[employee_id]['manager_id']) + 1
        return power_structure_level[employee_id]

    # Function to calculate the manager chain
    def calculate_manager_chain(employee_id):
        if employee_id not in manager_chain:
            if employee_dict[employee_id]['manager_id'] is None:
                manager_chain[employee_id] = 'None'
            else:
                manager_chain[employee_id] = calculate_manager_chain(employee_dict[employee_id]['manager_id']) + '>' + employee_dict[employee_id]['manager_name']
        return manager_chain[employee_id]

    # Function to calculate the subordinate count
    def calculate_subordinate_count(employee_id):
        if employee_id not in subordinate_count:
            subordinate_count[employee_id] = 0
            for employee in employees:
                if employee['manager_id'] == employee_id:
                    subordinate_count[employee_id] += 1 + calculate_subordinate_count(employee['employee_id'])
        return subordinate_count[employee_id]

    # Calculate the power structure level, manager chain, and subordinate count for each employee
    for employee in employees:
        calculate_power_structure_level(employee['employee_id'])
        calculate_manager_chain(employee['employee_id'])
        calculate_subordinate_count(employee['employee_id'])

    # Create the output tables
    power_structure_table = []
    subordinate_count_table = []
    manager_chain_table = []

    for employee in employees:
        power_structure_table.append({
            'employee_id': employee['employee_id'],
            'employee_name': employee['employee_name'],
            'level': power_structure_level[employee['employee_id']]
        })

        subordinate_count_table.append({
            'employee_id': employee['employee_id'],
            'employee_name': employee['employee_name'],
            'subordinate_count': subordinate_count[employee['employee_id']]
        })

        manager_chain_table.append({
            'employee_id': employee['employee_id'],
            'employee_name': employee['employee_name'],
            'manager_chain': manager_chain[employee['employee_id']]
        })

    return power_structure_table, subordinate_count_table, manager_chain_table

