import pandas as pd

def solve(employees):
    # Create a dictionary to store the manager of each employee
    manager_dict = {employee['employee_id']: employee['manager_id'] for employee in employees}

    # Create a dictionary to store the level of each employee
    level_dict = {}

    # Create a dictionary to store the subordinate count of each employee
    subordinate_count_dict = {}

    # Create a dictionary to store the manager chain of each employee
    manager_chain_dict = {}

    # Function to calculate the level of an employee
    def calculate_level(employee_id, level=1):
        if employee_id not in level_dict:
            if manager_dict[employee_id] is None:
                level_dict[employee_id] = level
            else:
                level_dict[employee_id] = calculate_level(manager_dict[employee_id], level + 1)
        return level_dict[employee_id]

    # Function to calculate the subordinate count of an employee
    def calculate_subordinate_count(employee_id):
        if employee_id not in subordinate_count_dict:
            subordinate_count = 0
            for employee in employees:
                if employee['manager_id'] == employee_id:
                    subordinate_count += 1 + calculate_subordinate_count(employee['employee_id'])
            subordinate_count_dict[employee_id] = subordinate_count
        return subordinate_count_dict[employee_id]

    # Function to calculate the manager chain of an employee
    def calculate_manager_chain(employee_id):
        if employee_id not in manager_chain_dict:
            if manager_dict[employee_id] is None:
                manager_chain_dict[employee_id] = 'None'
            else:
                manager_chain_dict[employee_id] = calculate_manager_chain(manager_dict[employee_id]) + '>' + manager_dict[employee_id] if manager_chain_dict[employee_id] != 'None' else manager_dict[employee_id]
        return manager_chain_dict[employee_id]

    # Calculate the level, subordinate count, and manager chain for each employee
    for employee in employees:
        calculate_level(employee['employee_id'])
        calculate_subordinate_count(employee['employee_id'])
        calculate_manager_chain(employee['employee_id'])

    # Create the result dataframes
    pecking_order_level = pd.DataFrame({'employee_id': [employee['employee_id'] for employee in employees], 'employee_name': [employee['employee_name'] for employee in employees], 'level': [level_dict[employee['employee_id']] for employee in employees]})
    underling_counting = pd.DataFrame({'employee_id': [employee['employee_id'] for employee in employees], 'employee_name': [employee['employee_name'] for employee in employees], 'subordinate_count': [subordinate_count_dict[employee['employee_id']] for employee in employees]})
    management_chain = pd.DataFrame({'employee_id': [employee['employee_id'] for employee in employees], 'employee_name': [employee['employee_name'] for employee in employees], 'manager_chain': [manager_chain_dict[employee['employee_id']] for employee in employees]})

    return pecking_order_level, underling_counting, management_chain

