class Employee:
    def __init__(self, employee_id, employee_name, manager_id):
        self.employee_id = employee_id
        self.employee_name = employee_name
        self.manager_id = manager_id
        self.subordinates = []

class Company:
    def __init__(self):
        self.employees = {}

    def add_employee(self, employee_id, employee_name, manager_id):
        self.employees[employee_id] = Employee(employee_id, employee_name, manager_id)

    def build_hierarchy(self):
        for employee in self.employees.values():
            if employee.manager_id in self.employees:
                self.employees[employee.manager_id].subordinates.append(employee)

    def calculate_levels(self):
        levels = {employee_id: 0 for employee_id in self.employees}
        queue = [(self.employees[1], 0)]
        while queue:
            employee, level = queue.pop(0)
            levels[employee.employee_id] = level
            for subordinate in employee.subordinates:
                queue.append((subordinate, level + 1))
        return {employee_id: level + 1 for employee_id, level in levels.items()}

    def calculate_subordinate_count(self):
        subordinate_count = {employee_id: 0 for employee_id in self.employees}
        for employee in self.employees.values():
            stack = [employee]
            while stack:
                current_employee = stack.pop()
                subordinate_count[current_employee.employee_id] += len(current_employee.subordinates)
                stack.extend(current_employee.subordinates)
        return subordinate_count

    def calculate_manager_chain(self):
        manager_chain = {employee_id: "" for employee_id in self.employees}
        for employee in self.employees.values():
            chain = []
            current_employee = employee
            while current_employee.manager_id in self.employees:
                chain.append(self.employees[current_employee.manager_id].employee_name)
                current_employee = self.employees[current_employee.manager_id]
            manager_chain[employee.employee_id] = " > ".join(reversed(chain))
        return manager_chain

